  private async processNext(): Promise<void> {
    // Check shutdown status before processing
    if (this.isShutdown) return;

    // If no tasks in priority queue and we have active workers, wait for one to finish
    if (this.priorityQueue.length === 0 && this.activeWorkers.size < this.options.concurrency) {
      await Promise.race(this.activeWorkers);
      return;
    }

    if (this.priorityQueue.length === 0) return;

    const nextTask = this.priorityQueue.shift();
    if (!nextTask) return;

    const task = nextTask.task;

    // Add to processing queue
    this.processingQueue.push(task);

    // Create worker promise
    const workerPromise = (async () => {
      try {
        await this.executeTask(task);

        // Remove from processing queue if still there
        const index = this.processingQueue.indexOf(task);
        if (index > -1) {
          this.processingQueue.splice(index, 1);
        }

        // Emit completed event
        const listeners = this.listeners.get('completed') ?? [];
        if (listeners.length > 0) {
          listeners.forEach(fn => fn({ type: 'completed', taskId: task.id }));
        }

      } catch (error) {
        // Remove from processing queue if still there
        const index = this.processingQueue.indexOf(task);
        if (index > -1) {
          this.processingQueue.splice(index, 1);
        }

        // Emit failed event
        const listeners = this.listeners.get('failed') ?? [];
        if (listeners.length > 0) {
          listeners.forEach(fn => fn({ type: 'failed', taskId: task.id, error }));
        }
      } finally {
        // Remove from active workers set
        const index = Array.from(this.activeWorkers).indexOf(workerPromise);
        if (index > -1) {
          this.activeWorkers.delete(workerPromise);
        }

        // Try to process next task
        await this.processNext();
      })();

    this.activeWorkers.add(workerPromise);
  }

  private async executeTask(task: Task<T>): Promise<void> {
    const startTime = Date.now();

    try {
      const result = await Promise.race([
        task.fn(),
        new Promise<never>((_, reject) => 
          setTimeout(() => reject(new Error(`Task ${task.id} timed out`)), task.timeout ?? this.options.timeout)
        )
      ]);

      // Task succeeded
    } catch (error) {
      const elapsed = Date.now() - startTime;

      if (elapsed > (task.timeout ?? this.options.timeout)) {
        throw new Error(`Task ${task.id} timed out after ${(task.timeout ?? this.options.timeout)}ms`);
      }

      // Handle retries with exponential backoff
      if (this.retryCount.get(task.id) < this.options.maxRetries) {
        const retryCount = this.retryCount.get(task.id)!;

        // Increment retry count
        this.retryCount.set(task.id, retryCount + 1);

        // Calculate delay: baseDelay * 2^(retry-1)
        const delay = this.options.baseDelay * Math.pow(2, retryCount - 1);

        // Emit retrying event
        const listeners = this.listeners.get('retrying') ?? [];
        if (listeners.length > 0) {
          listeners.forEach(fn => fn({ 
            type: 'retrying', 
            taskId: task.id,
            error: error as Error,
            retryCount: retryCount + 1,
            delay
          }));
        }

        // Wait before retrying
        await new Promise(resolve => setTimeout(resolve, delay));

        // Re-add to priority queue with same priority
        this.priorityQueue.push({ task, priority: task.priority ?? 0 });

        // Remove from processing queue if still there
        const index = this.processingQueue.indexOf(task);
        if (index > -1) {
          this.processingQueue.splice(index, 1);
        }

        throw error; // Re-throw to trigger retry logic in processNext
      } else {
        // Max retries exceeded, fail permanently
        throw error;
      }
    }
  }

  private retryCount = new Map<string, number>();

  public shutdown(): Promise<void> {
    this.isShutdown = true;

    // Cancel all active workers
    const promises = Array.from(this.activeWorkers);
    this.activeWorkers.clear();

    // Reject any pending operations in active workers
    for (const promise of promises) {
      if (!promise[Symbol.toStringTag]?.includes('Promise')) continue;

      // Try to cancel if AbortController is available, otherwise let them finish naturally
      // For simplicity, we'll just mark them as cancelled and wait for completion or timeout
      try {
        promise.catch(() => {});
      } catch (e) {
        // Ignore cancellation errors
      }
    }

    // Wait for all workers to complete their current tasks
    return Promise.all(Array.from(this.activeWorkers)).then(() => {
      // Emit drained event after shutdown completes
      const listeners = this.listeners.get('drained') ?? [];
      if (listeners.length > 0) {
        listeners.forEach(fn => fn({ type: 'drained' }));
      }
    });
  }

  public get queueSize(): number {
    return this.priorityQueue.length + this.processingQueue.length;
  }

  public get activeCount(): number {
    return this.activeWorkers.size;
  }
