export class StateMachine<
  T extends StateValue<any>,
  E extends EventName,
  C extends Context
> {
  private currentState: T;
  private context: C;
  private listeners: Map<E, Set<(event: E, oldState: T | null, newState: T) => void>>;
  private transitions: Record<T, StateConfig<T, E, C>>;

  constructor(options: StateMachineOptions<T, E, C>) {
    this.currentState = options.initial;
    this.context = options.context;
    this.listeners = new Map();
    this.transitions = options.states;

    // Trigger entry action for initial state if defined
    const initialConfig = this.transitions[this.currentState];
    if (initialConfig?.entry) {
      this.context = this.context as C & { [key: string]: unknown };
      const result = initialConfig.entry(this.context);
      if (result) {
        this.context = { ...this.context, ...result } as C;
      }
    }
  }

  private getTransition<T extends StateValue<any>, E extends EventName>(
    state: T,
    event: E
  ): TransitionDefinition<T, E, C> | undefined {
    const config = this.transitions[state];
    if (!config) return undefined;
    return config.on[event] as TransitionDefinition<T, E, C> | undefined;
  }

  private triggerEntryAction(state: T): void {
    const config = this.transitions[state];
    if (config?.entry) {
      const result = config.entry(this.context);
      if (result) {
        this.context = { ...this.context, ...result } as C;
      }
    }
  }

  private triggerExitAction(state: T): void {
    const config = this.transitions[state];
    if (config?.exit) {
      config.exit(this.context);
    }
  }

  public send(event: E): boolean {
    const oldState = this.currentState;
    const transition = this.getTransition(oldState, event);

    if (!transition) return false;

    // Handle Guard
    if (typeof transition === 'string') {
      this.currentState = transition as T;
      this.triggerEntryAction(this.currentState);
      this.notifyListeners(event, oldState, this.currentState);
      return true;
    } else {
      const guardResult = transition.guard ? transition.guard(this.context) : true;

      if (!guardResult) return false;

      let target: T | undefined = transition.target || oldState;

      // Handle Action before transition
      if (transition.action) {
        const result = transition.action(this.context);
        if (result) {
          this.context = { ...this.context, ...result } as C;
        }
      }

      if (target !== oldState) {
        this.currentState = target;
        this.triggerEntryAction(this.currentState);
        this.notifyListeners(event, oldState, this.currentState);
        return true;
      } else {
        // Guard passed but no state change or action caused loop back? 
        // Usually if target is same as current, we don't notify listeners for entry/exit of same state twice.
        // But if an action updated context, that's side effect.
        return true; 
      }
    }
  }

  private notifyListeners(event: E, oldState: T | null, newState: T): void {
    const listenerSet = this.listeners.get(event);
    if (listenerSet) {
      for (const listener of listenerSet) {
        try {
          listener(event, oldState, newState);
        } catch (err) {
          console.error(`Error in state machine listener for event ${event}:`, err);
        }
      }
    }
  }

  public on(event: E, listener: (event: E, oldState: T | null, newState: T) => void): () => void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(listener);

    return () => {
      this.listeners.get(event)?.delete(listener);
    };
  }

  public toJSON(): { state: T; context: C } {
    return {
      state: this.currentState,
      context: this.context,
    };
  }

  public fromJSON(json: { state: T; context: C }): void {
    this.currentState = json.state;
    this.context = json.context as C;
    // Re-trigger entry actions for restored state to ensure consistency if logic depends on init order
    // However, strictly speaking, restoring state usually implies the state is already entered.
    // But if we want full fidelity including side effects of entry:
